import Foundation

struct Book {
    let title: String
    let pageCount: Int
    let isRead: Bool
}

let books = [
    Book(title: "Swift Guide", pageCount: 300, isRead: true),
    Book(title: "Data Patterns", pageCount: 450, isRead: false),
    Book(title: "Concurrency", pageCount: 200, isRead: true)
]

let sorted = books.sorted { $0.pageCount < $1.pageCount }
let filtered = books.filter { $0.isRead }

print("Sorted by pages:")
for book in sorted { print("  \(book.title): \(book.pageCount)p") }

print("Read books: \(filtered.count)")
